const industryConfig = {
  industry: 'journalism',
  label: 'Journalism & Media',
  lookback_days: 7,
  focus_rotation: [
    {
      week: 3,
      slug: 'tooling-workflow',
      label: 'Tooling & Workflow',
      keywords: ['cms', 'workflow', 'publishing', 'editorial tools', 'collaboration', 'newsroom systems'],
    },
  ],
  sources: [
    {
      name: 'Nieman Lab',
      type: 'rss',
      url: 'https://www.niemanlab.org/feed/',
      focus_areas: ['tooling-workflow', 'ai-automation'],
    },
    {
      name: 'Poynter',
      type: 'rss',
      url: 'https://www.poynter.org/feed/',
      focus_areas: ['tooling-workflow', 'trust-misinformation'],
    },
    {
      name: 'r/journalism',
      type: 'reddit',
      subreddit: 'journalism',
      sort: 'hot',
      limit: 25,
      focus_areas: ['all'],
    },
  ],
};

const selectedFocus = industryConfig.focus_rotation[0];
const selectedRssSources = industryConfig.sources
  .filter((source) => source.type === 'rss')
  .filter((source) => source.focus_areas.includes(selectedFocus.slug) || source.focus_areas.includes('all'));

if (selectedRssSources.length === 0) {
  throw new Error(`No RSS sources found for focus ${selectedFocus.slug}`);
}

return [
  {
    json: {
      run_context: {
        industry_slug: industryConfig.industry,
        industry_label: industryConfig.label,
        focus_slug: selectedFocus.slug,
        focus_label: selectedFocus.label,
        week_number: selectedFocus.week,
        user_context: 'Editors keep describing publishing systems as brittle and fragmented.',
        lookback_days: industryConfig.lookback_days,
      },
      industry_config: industryConfig,
      selected_rss_sources: selectedRssSources,
      config_snapshot_note: 'Mocked subset of config/journalism.json for workflow importability. Replace with a real config-loading step in a later slice.',
    },
  },
];

const seedNode = $('Seed Mock Run Context').first().json;
const source = seedNode.selected_rss_sources[0];

if (!source) {
  return [];
}

return [
  {
    json: {
      source_name: source.name,
      source_type: source.type,
      source_url: source.url,
    },
  },
];

const source = $('Prepare RSS Source 1').first().json;
const maxIntermediateContentLength = 6000;

const normalizePublishedAt = (value) => {
  if (!value) {
    return null;
  }

  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime()) ? null : parsed.toISOString();
};

const stripHtml = (value) => value.replace(/<[^>]+>/g, ' ');
const normalizeWhitespace = (value) => value.replace(/\s+/g, ' ').trim();
const toPlainText = (value) => normalizeWhitespace(stripHtml(typeof value === 'string' ? value : ''));
const truncateContent = (value, maxLength) => {
  if (value.length <= maxLength) {
    return { text: value, truncated: false };
  }

  const ellipsis = '...';
  if (maxLength <= ellipsis.length) {
    return {
      text: ellipsis.slice(0, maxLength),
      truncated: true,
    };
  }

  return {
    text: `${value.slice(0, maxLength - ellipsis.length).trimEnd()}${ellipsis}`,
    truncated: true,
  };
};

return $input.all().map((item) => {
  const title = toPlainText(item.json.title) || 'Untitled feed item';
  const rawContent = item.json.contentSnippet ?? item.json.content ?? item.json.summary ?? item.json.description ?? '';
  const plainTextContent = toPlainText(rawContent);
  const { text: contentInput, truncated: contentInputTruncated } = truncateContent(plainTextContent, maxIntermediateContentLength);

  return {
    json: {
      source_name: source.source_name,
      source_type: source.source_type,
      source_url: item.json.link ?? item.json.guid ?? source.source_url,
      feed_source_url: source.source_url,
      title,
      content_input: contentInput,
      content_input_truncated: contentInputTruncated,
      published_at: normalizePublishedAt(item.json.isoDate ?? item.json.pubDate ?? null),
    },
  };
});

const seedNode = $('Seed Mock Run Context').first().json;
const source = seedNode.selected_rss_sources[1];

if (!source) {
  return [];
}

return [
  {
    json: {
      source_name: source.name,
      source_type: source.type,
      source_url: source.url,
    },
  },
];

const source = $('Prepare RSS Source 2').first().json;
const maxIntermediateContentLength = 6000;

const normalizePublishedAt = (value) => {
  if (!value) {
    return null;
  }

  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime()) ? null : parsed.toISOString();
};

const stripHtml = (value) => value.replace(/<[^>]+>/g, ' ');
const normalizeWhitespace = (value) => value.replace(/\s+/g, ' ').trim();
const toPlainText = (value) => normalizeWhitespace(stripHtml(typeof value === 'string' ? value : ''));
const truncateContent = (value, maxLength) => {
  if (value.length <= maxLength) {
    return { text: value, truncated: false };
  }

  const ellipsis = '...';
  if (maxLength <= ellipsis.length) {
    return {
      text: ellipsis.slice(0, maxLength),
      truncated: true,
    };
  }

  return {
    text: `${value.slice(0, maxLength - ellipsis.length).trimEnd()}${ellipsis}`,
    truncated: true,
  };
};

return $input.all().map((item) => {
  const title = toPlainText(item.json.title) || 'Untitled feed item';
  const rawContent = item.json.contentSnippet ?? item.json.content ?? item.json.summary ?? item.json.description ?? '';
  const plainTextContent = toPlainText(rawContent);
  const { text: contentInput, truncated: contentInputTruncated } = truncateContent(plainTextContent, maxIntermediateContentLength);

  return {
    json: {
      source_name: source.source_name,
      source_type: source.source_type,
      source_url: item.json.link ?? item.json.guid ?? source.source_url,
      feed_source_url: source.source_url,
      title,
      content_input: contentInput,
      content_input_truncated: contentInputTruncated,
      published_at: normalizePublishedAt(item.json.isoDate ?? item.json.pubDate ?? null),
    },
  };
});

const seedNode = $('Seed Mock Run Context').first().json;
const runContext = seedNode.run_context;
const industryConfig = seedNode.industry_config;
const selectedRssSources = seedNode.selected_rss_sources;
const focusKeywords = industryConfig.focus_rotation.find((focus) => focus.slug === runContext.focus_slug)?.keywords ?? [];
const maxContentLength = 4000;
const maxLiveSourceItems = 6;
const lookbackDays = Number(runContext.lookback_days) || 0;
const lookbackCutoff = lookbackDays > 0
  ? new Date(Date.now() - lookbackDays * 24 * 60 * 60 * 1000)
  : null;

const isWithinLookback = (publishedAt) => {
  if (!lookbackCutoff) {
    return true;
  }

  if (!publishedAt) {
    return false;
  }

  return new Date(publishedAt).getTime() >= lookbackCutoff.getTime();
};

const truncateContent = (value, maxLength) => {
  if (value.length <= maxLength) {
    return { text: value, truncated: false };
  }

  const ellipsis = '...';
  if (maxLength <= ellipsis.length) {
    return {
      text: ellipsis.slice(0, maxLength),
      truncated: true,
    };
  }

  return {
    text: `${value.slice(0, maxLength - ellipsis.length).trimEnd()}${ellipsis}`,
    truncated: true,
  };
};

const normalizedItems = $input.all().map((item, index) => {
  const feedItem = item.json;
  const { text: content, truncated: contentTruncated } = truncateContent(feedItem.content_input ?? '', maxContentLength);
  const haystack = `${feedItem.title} ${content}`.toLowerCase();

  return {
    id: `source-${index + 1}`,
    source_name: feedItem.source_name,
    source_type: feedItem.source_type,
    source_url: feedItem.source_url,
    feed_source_url: feedItem.feed_source_url,
    title: feedItem.title,
    content,
    content_truncated: feedItem.content_input_truncated || contentTruncated,
    published_at: feedItem.published_at,
    matched_keywords: focusKeywords.filter((keyword) => haystack.includes(keyword.toLowerCase())),
  };
});

const lookbackItems = normalizedItems.filter((item) => isWithinLookback(item.published_at));
const keywordMatchedItems = lookbackItems.filter((item) => item.matched_keywords.length > 0);
const sourceCandidates = keywordMatchedItems.length > 0
  ? keywordMatchedItems
  : lookbackItems.length > 0
    ? lookbackItems.slice(0, maxLiveSourceItems)
    : normalizedItems.slice(0, maxLiveSourceItems);
const sourceBatch = sourceCandidates.map((item, index) => ({
  ...item,
  id: `source-${index + 1}`,
}));
const contributingSourceCount = new Set(normalizedItems.map((item) => item.feed_source_url)).size;

const sourceIngestionNote = keywordMatchedItems.length > 0
  ? `Source batch built from ${contributingSourceCount} of ${selectedRssSources.length} configured RSS sources within the lookback window and filtered by focus keywords. Content is normalized to plain text and bounded for prompt use. Live pass-1 extraction is currently capped at ${maxLiveSourceItems} source documents per run and throttled between requests.`
  : lookbackItems.length > 0
    ? `No live RSS items within the lookback window matched the focus keywords, so the workflow kept the first ${maxLiveSourceItems} recent feed items from ${contributingSourceCount} of ${selectedRssSources.length} configured RSS sources as a fallback. Content is normalized to plain text and bounded for prompt use.`
    : `No live RSS items fell within the configured lookback window, so the workflow kept the first ${maxLiveSourceItems} feed items from ${contributingSourceCount} of ${selectedRssSources.length} configured RSS sources as a fallback. Content is normalized to plain text and bounded for prompt use.`;

return [
  {
    json: {
      run_context: runContext,
      industry_config: industryConfig,
      selected_rss_sources: selectedRssSources,
      config_snapshot_note: seedNode.config_snapshot_note,
      focus_keywords: focusKeywords,
      lookback_cutoff: lookbackCutoff ? lookbackCutoff.toISOString() : null,
      contributing_source_count: contributingSourceCount,
      source_ingestion_note: sourceIngestionNote,
      source_batch: sourceBatch,
    },
  },
];

const templateRef = 'n8n/prompts/pass-1-extraction.md';
const { run_context, source_batch } = $json;

const extractionRequests = source_batch.map((source) => {
  const renderedPrompt = [
    'System: You are analyzing content from journalism industry sources.',
    `This week\'s focus: ${run_context.focus_label}.`,
    `The person running this analysis added the following context`,
    `and hunches to guide your attention: "${run_context.user_context}"`,
    'Weight pain points related to their observations more heavily.',
    '',
    'Extract any professional pain points, unmet needs, or recurring',
    'frustrations mentioned or implied. Return JSON only.',
    '',
    '{',
    '  "pain_points": [',
    '    {',
    '      "description": "string - the pain point in plain language",',
    '      "who_feels_it": "string - which role or group",',
    '      "evidence_quote": "string - short supporting excerpt",',
    '      "severity": "low | medium | high"',
    '    }',
    '  ],',
    '  "source_summary": "string - 1-2 sentence summary of the source content"',
    '}',
    '',
    'If no pain points are present, return {"pain_points": [], "source_summary": "..."}',
    '',
    `Source title: ${source.title}`,
    `Source content: ${source.content}`,
  ].join('\n');

  return {
    source_id: source.id,
    source_name: source.source_name,
    source_url: source.source_url,
    source_type: source.source_type,
    prompt_template_ref: templateRef,
    rendered_prompt: renderedPrompt,
    source_document: source,
  };
});

return [
  {
    json: {
      ...$json,
      extraction_requests: extractionRequests,
    },
  },
];

const defaultModel = 'gemini-3.1-flash-lite-preview';
const extractionSchema = {
  type: 'object',
  additionalProperties: false,
  properties: {
    pain_points: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: {
          description: { type: 'string' },
          who_feels_it: { type: 'string' },
          evidence_quote: { type: 'string' },
          severity: {
            type: 'string',
            enum: ['low', 'medium', 'high']
          }
        },
        required: ['description', 'who_feels_it', 'evidence_quote', 'severity']
      }
    },
    source_summary: { type: 'string' }
  },
  required: ['pain_points', 'source_summary']
};

return $json.extraction_requests.map((request) => ({
  json: {
    ...request,
    llm_provider: 'gemini',
    llm_model: defaultModel,
    gemini_request: {
      contents: [
        {
          parts: [
            {
              text: request.rendered_prompt
            }
          ]
        }
      ],
      generationConfig: {
        temperature: 0.2,
        responseMimeType: 'application/json',
        responseSchema: extractionSchema
      }
    }
  }
}));

const requestItems = $('Prepare Live Pass 1 Calls').all();

const getResponseText = (response) => {
  const candidates = Array.isArray(response.candidates) ? response.candidates : [];

  for (const candidate of candidates) {
    const parts = candidate?.content?.parts;

    if (!Array.isArray(parts)) {
      continue;
    }

    for (const part of parts) {
      if (typeof part?.text === 'string') {
        return part.text;
      }
    }
  }

  throw new Error('Gemini pass-1 response did not include structured text output.');
};

return $input.all().map((item, index) => {
  const request = requestItems[index]?.json;

  if (!request) {
    throw new Error(`Missing request context for Gemini response index ${index}.`);
  }

  const response = item.json;

  let responseText;
  try {
    responseText = getResponseText(response);
  } catch (error) {
    let rawResponseSnippet = '';

    try {
      rawResponseSnippet = JSON.stringify(response).slice(0, 500);
    } catch (stringifyError) {
      rawResponseSnippet = String(response).slice(0, 500);
    }

    throw new Error(
      `Gemini pass-1 response did not include structured text output for source_id=${request.source_id || 'unknown'} ` +
      `source_url=${request.source_url || 'unknown'} model=${request.llm_model || 'unknown'} index=${index}. ` +
      `Underlying error: ${error.message}. Raw response snippet: ${rawResponseSnippet}`,
    );
  }

  let parsed;
  try {
    parsed = JSON.parse(responseText);
  } catch (error) {
    const rawTextSnippet = responseText.slice(0, 500);

    throw new Error(
      `Failed to parse Gemini pass-1 JSON for source_id=${request.source_id || 'unknown'} ` +
      `source_url=${request.source_url || 'unknown'} model=${request.llm_model || 'unknown'} index=${index}. ` +
      `Raw text snippet: ${rawTextSnippet}. Error: ${error.message}`,
    );
  }

  const painPoints = Array.isArray(parsed.pain_points) ? parsed.pain_points : [];

  return {
    json: {
      source_id: request.source_id,
      source_name: request.source_name,
      source_url: request.source_url,
      source_summary: typeof parsed.source_summary === 'string' ? parsed.source_summary : '',
      pain_points: painPoints.map((painPoint) => ({
        description: painPoint.description,
        who_feels_it: painPoint.who_feels_it,
        evidence_quote: painPoint.evidence_quote,
        severity: painPoint.severity,
      })),
      llm_provider: request.llm_provider,
      llm_model: request.llm_model,
    },
  };
});

const workflowState = $('Build Pass 1 Prompt Payloads').first().json;
const extractionResults = $input.all().map((item) => item.json);

return [
  {
    json: {
      ...workflowState,
      extraction_results: extractionResults,
      pain_point_count: extractionResults.reduce((total, result) => total + result.pain_points.length, 0),
      pass_1_note: extractionResults.length > 0
        ? `Pass-1 extraction completed with live Gemini calls across ${extractionResults.length} source documents.`
        : 'Pass-1 extraction completed with no source documents selected for extraction.',
      pass_1_models: [...new Set(extractionResults.map((result) => result.llm_model))],
    },
  },
];

const publishedAt = new Date().toISOString();

const briefing = {
  industry_context: 'Journalism tooling pain is showing up as a workflow problem rather than a single-software problem. Teams are spending time bridging gaps between editorial, publishing, and distribution tools.',
  key_pain_points: [
    {
      description: 'Publishing systems force manual workarounds.',
      signal_strength: 9,
      demand_velocity: 'growing',
      who_feels_it: 'Editors and reporters',
    },
  ],
  business_ideas: [
    {
      pain_point: 'Publishing systems force manual workarounds.',
      concept: 'A newsroom workflow layer that coordinates approvals and downstream publish targets without forcing a CMS replacement.',
      whos_trying: 'General editorial workflow tools',
      non_obvious_angle: 'Treat newsletter and social outputs as first-class release targets.',
    },
  ],
  dig_deeper: {
    source_links: $json.source_batch.map((source) => ({
      name: source.source_name,
      url: source.source_url,
      note: source.title,
    })),
    communities: ['r/journalism', 'Local newsroom operators', 'Newsletter-first publishers'],
    related_reading: ['Look for places where workflow pain is really a distribution bottleneck in disguise.'],
  },
};

const briefingsRowPendingResolution = {
  industry_id: null,
  industry_slug: $json.run_context.industry_slug,
  focus_slug: $json.run_context.focus_slug,
  focus_label: $json.run_context.focus_label,
  focus_was_custom: false,
  user_context: $json.run_context.user_context,
  week_number: $json.run_context.week_number,
  briefing,
  source_count: $json.source_batch.length,
  pain_point_count: $json.aggregated_pain_points.length,
  published_at: publishedAt,
};

const painPointRowsPendingBriefingId = $json.aggregated_pain_points.map((painPoint) => ({
  briefing_id: null,
  description: painPoint.description,
  who_feels_it: painPoint.who_feels_it,
  evidence_quote: painPoint.evidence_quote,
  severity: painPoint.severity,
  source_name: painPoint.source_name,
  source_url: painPoint.source_url,
  extracted_at: publishedAt,
}));

return [
  {
    json: {
      run_context: $json.run_context,
      industry_config: $json.industry_config,
      selected_rss_sources: $json.selected_rss_sources,
      config_snapshot_note: $json.config_snapshot_note,
      source_ingestion_note: $json.source_ingestion_note,
      source_plan: $json.source_batch,
      prompt_requests: {
        pass_1: $json.extraction_requests,
        pass_2: $json.synthesis_request,
      },
      extraction_results: $json.extraction_results,
      briefing,
      persistence_payloads: {
        resolution_notes: [
          'Resolve run_context.industry_slug to industries.id before inserting a briefing row.',
          'Use the inserted briefing.id as briefing_id on each pain point row before insert.'
        ],
        briefings_row_pending_resolution: briefingsRowPendingResolution,
        pain_points_rows_pending_briefing_id: painPointRowsPendingBriefingId,
      },
    },
  },
];
